def match(pattern, text):
    p = pattern
    n = len(p)
    pos = [0]

    def peek():
        return p[pos[0]] if pos[0] < n else None

    def advance():
        c = p[pos[0]]
        pos[0] += 1
        return c

    def parse_alt():
        parts = [parse_concat()]
        while peek() == '|':
            advance()
            parts.append(parse_concat())
        if len(parts) == 1:
            return parts[0]
        return ('alt', parts)

    def parse_concat():
        nodes = []
        while True:
            c = peek()
            if c is None or c == '|' or c == ')':
                break
            nodes.append(parse_quant())
        return ('concat', nodes)

    def parse_quant():
        atom = parse_atom()
        c = peek()
        if c == '*':
            advance()
            return ('star', atom)
        if c == '+':
            advance()
            return ('plus', atom)
        if c == '?':
            advance()
            return ('opt', atom)
        return atom

    def parse_atom():
        c = peek()
        if c == '(':
            advance()
            node = parse_alt()
            advance()  # consume ')'
            return node
        if c == '[':
            return parse_class()
        if c == '.':
            advance()
            return ('any',)
        advance()
        return ('char', c)

    def parse_class():
        advance()  # consume '['
        negated = False
        if peek() == '^':
            advance()
            negated = True
        ranges = []
        while peek() is not None and peek() != ']':
            ch = advance()
            if peek() == '-' and pos[0] + 1 < n and p[pos[0] + 1] != ']':
                advance()  # consume '-'
                ch2 = advance()
                ranges.append((ch, ch2))
            else:
                ranges.append((ch, ch))
        advance()  # consume ']'
        return ('class', negated, ranges)

    ast = parse_alt()

    states = []

    def emit(state):
        states.append(state)
        return len(states) - 1

    def patch(outs, target):
        for (i, slot) in outs:
            states[i][slot] = target

    def comp(node):
        t = node[0]
        if t == 'char':
            ch = node[1]
            i = emit(['char', (lambda c, ch=ch: c == ch), None])
            return i, [(i, 2)]
        if t == 'any':
            i = emit(['char', (lambda c: True), None])
            return i, [(i, 2)]
        if t == 'class':
            neg = node[1]
            rngs = node[2]

            def pred(c, neg=neg, rngs=rngs):
                inr = False
                for a, b in rngs:
                    if a <= c <= b:
                        inr = True
                        break
                return inr != neg

            i = emit(['char', pred, None])
            return i, [(i, 2)]
        if t == 'concat':
            nodes = node[1]
            if not nodes:
                i = emit(['split', None, None])
                return i, [(i, 1), (i, 2)]
            start, outs = comp(nodes[0])
            for sub in nodes[1:]:
                s2, o2 = comp(sub)
                patch(outs, s2)
                outs = o2
            return start, outs
        if t == 'alt':
            start, outs = comp(node[1][0])
            for sub in node[1][1:]:
                s2, o2 = comp(sub)
                i = emit(['split', start, s2])
                start = i
                outs = outs + o2
            return start, outs
        if t == 'star':
            ss, so = comp(node[1])
            i = emit(['split', ss, None])
            patch(so, i)
            return i, [(i, 2)]
        if t == 'plus':
            ss, so = comp(node[1])
            i = emit(['split', ss, None])
            patch(so, i)
            return ss, [(i, 2)]
        if t == 'opt':
            ss, so = comp(node[1])
            i = emit(['split', ss, None])
            return i, so + [(i, 2)]

    start, outs = comp(ast)
    m = emit(['match'])
    patch(outs, m)

    def add(lst, s, seen):
        stack = [s]
        while stack:
            cur = stack.pop()
            if cur in seen:
                continue
            seen.add(cur)
            st = states[cur]
            if st[0] == 'split':
                stack.append(st[2])
                stack.append(st[1])
            else:
                lst.append(cur)

    clist = []
    seen = set()
    add(clist, start, seen)
    for ch in text:
        nlist = []
        seen = set()
        for s in clist:
            st = states[s]
            if st[0] == 'char' and st[1](ch):
                add(nlist, st[2], seen)
        clist = nlist
    for s in clist:
        if states[s][0] == 'match':
            return True
    return False
